#!/usr/bin/env node
/**
 * Mirrors SVG diagrams from ../docs/images/ into public/diagrams/ so Astro can
 * serve them as static assets. Runs automatically on `pnpm predev` and
 * `pnpm prebuild`. The destination is .gitignored; the source of truth stays
 * in ../docs/images/ (regenerated by .github/workflows/render-diagrams.yml).
 */
import { mkdir, readdir, copyFile, stat } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import { dirname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const SOURCE_DIR = resolve(__dirname, '..', '..', 'docs', 'images');
const TARGET_DIR = resolve(__dirname, '..', 'public', 'diagrams');

async function main() {
  if (!existsSync(SOURCE_DIR)) {
    console.warn(`[sync-diagrams] Source directory not found: ${SOURCE_DIR}`);
    console.warn('[sync-diagrams] Skipping. Run the PlantUML renderer first (see .github/workflows/render-diagrams.yml).');
    return;
  }

  await mkdir(TARGET_DIR, { recursive: true });

  const entries = await readdir(SOURCE_DIR);
  const svgs = entries.filter((f) => f.toLowerCase().endsWith('.svg'));

  if (svgs.length === 0) {
    console.warn(`[sync-diagrams] No SVG files found in ${SOURCE_DIR}.`);
    return;
  }

  let copied = 0;
  for (const file of svgs) {
    const src = join(SOURCE_DIR, file);
    const dst = join(TARGET_DIR, file);
    const srcStat = await stat(src);
    if (!srcStat.isFile()) continue;
    await copyFile(src, dst);
    copied += 1;
  }

  console.log(`[sync-diagrams] Synced ${copied} SVG file(s) to public/diagrams/`);
}

main().catch((err) => {
  console.error('[sync-diagrams] Failed:', err);
  process.exit(1);
});
